/**
 * Static Universal Router recipe for swapping $5 USDC → $WORD on Base.
 *
 * Route: V3 USDC/WETH (0.05% fee) → V4 WETH/WORD (Clanker v4 pool).
 * Generated via Uniswap's universal-router-sdk on M5-usdc-premium-
 * fork-test and verified by a passing forge fork test at 955k gas.
 *
 * These bytes are pool-state-independent: the V3 input encodes a
 * fixed 5_000_000 USDC amountIn + USDC→WETH path, and the V4 input
 * uses OPEN_DELTA + CONTRACT_BALANCE sentinels (amountIn=0 resolved
 * at execution) so the bytes stay correct regardless of current
 * sqrtPriceX96 drift.
 *
 * Regenerate on the fork-test branch via:
 *   cd scripts/swap-recipe && bun run compute-recipe.ts --json
 * only if the pool key (hook / fee / tickSpacing) changes.
 */

/*
 * WORD/WETH v4 Clanker pool parameters (reference — encoded into the
 * SWAP_RECIPE.inputs[1] bytes below, not read at runtime).
 * Discovered via Uniswap v4 PoolManager Initialize event on Base:
 *   poolId      = 0xc5db937916d2c6f96142a6886ba8b5b74e14949c9cc1080a676ab2a5eb1ea275
 *   currency0   = 0x304e649e69979298BD1AEE63e175ADf07885fb4b ($WORD)
 *   currency1   = 0x4200000000000000000000000000000000000006 (WETH)
 *   fee         = 0x800000 (DYNAMIC_FEE_FLAG — Clanker sets fee at swap time)
 *   tickSpacing = 200
 *   hooks       = 0xd60D6B218116cFd801E28F78d011a203D2b068Cc
 */

/** Bytes for `GriddlePremium.setSwapConfig(commands, inputs)`. */
export const SWAP_RECIPE = {
  commands: '0x0010' as `0x${string}`,
  inputs: [
    // Leg 1: V3_SWAP_EXACT_IN
    //   recipient: ADDRESS_THIS (sentinel 0x02 — UR holds WETH for leg 2)
    //   amountIn:  5_000_000 (6-dec USDC)
    //   amountOutMin: 0 (contract enforces final minWordOut)
    //   path: USDC 0x833589… → fee 500 (0x0001f4) → WETH 0x4200…
    //   payerIsUser: true (pull USDC from GriddlePremium via Permit2)
    ('') as `0x${string}`,

    // Leg 2: V4_SWAP wrapping (SETTLE + SWAP_EXACT_IN + TAKE)
    //   SETTLE:  WETH, amount=CONTRACT_BALANCE (sentinel 0), payerIsUser=false
    //   SWAP_EXACT_IN: path [WETH→WORD via Clanker pool], amountIn=OPEN_DELTA (0)
    //   TAKE:    WORD, recipient=MSG_SENDER (= GriddlePremium), amount=0
    ('') as `0x${string}`,
  ],
} as const;
